            model = model_class(config).to(torch_device)  # noqa: F841

            # check that forward signature matches parent
            signature = inspect.signature(model.forward)
            # signature parameters are ordered differently than the class attributes
            parameters = [param for param in signature.parameters.values()]
            self.assertEqual(len(parameters), len(self.model_tester.forward_signature))

            for parameter, (parameter_name, parameter_info) in zip(parameters, self.model_tester.forward_signature):
                # check the parameter names and types
                self.assertEqual(parameter.name, parameter_name)
                self.assertEqual(parameter.annotation, parameter_info["annotation"])
                if parameter_name not in ["output_attentions", "output_hidden_states", "return_dict"]:
                    self.assertEqual(parameter.default, parameter_info["default"])
                else:
